import { EventEmitter } from 'events';
import type { KeyvStoreAdapter, KeyvStorageGetResult } from 'keyv';

interface CacheItem {
  value: any;
  expires?: number;
}

class MyCustomStore extends EventEmitter implements KeyvStoreAdapter {
  private store: Map<string, CacheItem>;
  public namespace?: string;

  constructor(options: any = {}) {
    super();
    this.store = new Map();
    this.namespace = options.namespace;
  }

  async get<Value>(key: string): Promise<KeyvStorageGetResult<Value> | undefined> {
    const data = this.store.get(key);

    if (!data) {
      return undefined;
    }

    // Check if expired
    if (data.expires && Date.now() > data.expires) {
      this.store.delete(key);
      return undefined;
    }

    return data as KeyvStorageGetResult<Value>;
  }

  async set(key: string, value: any, ttl?: number): Promise<boolean> {
    const data: CacheItem = {
      value,
      expires: ttl ? Date.now() + ttl : undefined,
    };
    this.store.set(key, data);
    return true;
  }

  async delete(key: string): Promise<boolean> {
    return this.store.delete(key);
  }

  async clear(): Promise<void> {
    this.store.clear();
  }

  // Optional: Implement batch operations for better performance
  async getMany<Value>(keys: string[]): Promise<Array<KeyvStorageGetResult<Value | undefined>>> {
    const values: Array<KeyvStorageGetResult<Value | undefined>> = [];
    for (const key of keys) {
      values.push(await this.get<Value>(key));
    }
    return values;
  }

  async deleteMany(keys: string[]): Promise<boolean[]> {
    return keys.map((key) => this.store.delete(key));
  }

  async has(key: string): Promise<boolean> {
    const data = this.store.get(key);
    if (!data) {
      return false;
    }
    if (data.expires && Date.now() > data.expires) {
      this.store.delete(key);
      return false;
    }
    return true;
  }

  async disconnect(): Promise<void> {
    this.store.clear();
  }
}

export default MyCustomStore;

